/**
 * Подтема SddsSbComTheme.OnLight
 */
@Composable
public fun SddsSbComTheme.OnLight(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalSddsSbComColors.current
    val overrideColors = currentColors.copyAttrs(OnLightColorsOverride)
    val currentGradients = LocalSddsSbComGradients.current
    val overrideGradients = currentGradients.copyAttrs(OnLightGradientsOverride)
    SddsSbComTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
